import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { Biography } from './components/Biography';
import { LegacyProjects } from './components/LegacyProjects';
import { Gallery } from './components/Gallery';
import { MemoryWall } from './components/MemoryWall';
import { Footer } from './components/Footer';
import { ThankYou } from './components/ThankYou';

function App() {
  const [currentPath, setCurrentPath] = useState(window.location.pathname);

  useEffect(() => {
    const handleLocationChange = () => {
      setCurrentPath(window.location.pathname);
      window.scrollTo(0, 0);
    };

    window.addEventListener('popstate', handleLocationChange);
    // Listen for custom navigation events
    window.addEventListener('navigate', handleLocationChange);

    return () => {
      window.removeEventListener('popstate', handleLocationChange);
      window.removeEventListener('navigate', handleLocationChange);
    };
  }, []);

  const navigate = (path: string) => {
    window.history.pushState({}, '', path);
    window.dispatchEvent(new Event('navigate'));
  };

  const isThankYouPage = currentPath === '/thank-you';

  return (
    <div className="min-h-screen bg-gray-50 font-sans" dir="rtl">
      <Navbar currentPath={currentPath} onNavigate={navigate} />
      <main>
        {isThankYouPage ? (
          <div className="pt-20 min-h-screen">
            <ThankYou />
          </div>
        ) : (
          <>
            <Hero />
            <Biography />
            <LegacyProjects />
            <Gallery />
            <MemoryWall />
          </>
        )}
      </main>
      <Footer onNavigate={navigate} />
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { SectionId } from '../types';
import { Menu, X } from 'lucide-react';

interface NavbarProps {
  currentPath: string;
  onNavigate: (path: string) => void;
}

export const Navbar: React.FC<NavbarProps> = ({ currentPath, onNavigate }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isHome = currentPath === '/';

  const navLinks = [
    { label: 'ראשי', href: '/', id: SectionId.HERO },
    { label: 'סיפור חייו', href: '/#bio', id: SectionId.BIO },
    { label: 'פרויקטים', href: '/#projects', id: SectionId.PROJECTS },
    { label: 'תודות', href: '/thank-you', id: SectionId.THANK_YOU },
    { label: 'גלריה', href: '/#gallery', id: SectionId.GALLERY },
    { label: 'זכרונות', href: '/#memories', id: SectionId.MEMORIES },
  ];

  const handleLinkClick = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    const path = href.split('#')[0];
    const hash = href.split('#')[1];

    if (path === currentPath) {
      if (hash) {
        e.preventDefault();
        const element = document.getElementById(hash);
        element?.scrollIntoView({ behavior: 'smooth' });
      } else if (path === '/') {
        e.preventDefault();
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }
    } else {
      e.preventDefault();
      onNavigate(path);
      // If there's a hash, we wait for navigation then scroll
      if (hash) {
        setTimeout(() => {
          const element = document.getElementById(hash);
          element?.scrollIntoView({ behavior: 'smooth' });
        }, 100);
      }
    }
    setIsMobileMenuOpen(false);
  };

  const navTextColor = isScrolled || !isHome ? 'text-memorial-dark' : 'text-white';
  const navBgColor = isScrolled || !isHome ? 'bg-white shadow-md' : 'bg-transparent';

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${navBgColor} py-3`}>
      <div className="container mx-auto px-4 flex justify-between items-center">
        <a 
          href="/" 
          onClick={(e) => handleLinkClick(e, '/')}
          className={`font-display font-bold text-xl transition-colors ${navTextColor}`}
        >
          רונאל בן משה ז"ל
        </a>

        {/* Desktop Menu */}
        <div className="hidden md:flex gap-8">
          {navLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              onClick={(e) => handleLinkClick(e, link.href)}
              className={`font-medium text-sm transition-colors duration-300 hover:text-memorial-gold ${
                isScrolled || !isHome ? 'text-gray-600' : 'text-gray-200'
              }`}
            >
              {link.label}
            </a>
          ))}
        </div>

        {/* Mobile Menu Button */}
        <button 
          className="md:hidden"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? (
            <X className={navTextColor} />
          ) : (
            <Menu className={navTextColor} />
          )}
        </button>
      </div>

      {/* Mobile Menu Dropdown */}
      {isMobileMenuOpen && (
        <div className="absolute top-full left-0 right-0 bg-white shadow-lg md:hidden p-4 flex flex-col gap-4 border-t">
          {navLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              onClick={(e) => handleLinkClick(e, link.href)}
              className="text-gray-800 text-lg py-2 border-b border-gray-100 last:border-0"
            >
              {link.label}
            </a>
          ))}
        </div>
      )}
    </nav>
  );
};

